```javascript
const { Client, GatewayIntentBits, REST, Routes } = require('discord.js');
require('dotenv').config();

// Create a new client instance
const client = new Client({
    intents: [GatewayIntentBits.Guilds, GatewayIntentBits.GuildMembers],
});

// Your bot token and client ID from the Discord Developer Portal
const CLIENT_ID = process.env.CLIENT_ID; // Your bot's client ID
const GUILD_ID = process.env.GUILD_ID;   // Your guild (server) ID
const TOKEN = process.env.TOKEN;          // Your bot's token

// Function to register commands
const registerCommands = async () => {
    const commands = [
        {
            name: 'ban',
            description: 'Ban a user from the server',
            options: [
                {
                    name: 'user',
                    type: 6, // USER type
                    description: 'The user to ban',
                    required: true,
                },
                {
                    name: 'reason',
                    type: 3, // STRING type
                    description: 'The reason for the ban',
                    required: false,
                },
            ],
        },
    ];

    const rest = new REST({ version: '9' }).setToken(TOKEN);

    try {
        console.log('Started refreshing application (/) commands.');

        await rest.put(Routes.applicationGuildCommands(CLIENT_ID, GUILD_ID), {
            body: commands,
        });

        console.log('Successfully reloaded application (/) commands.');
    } catch (error) {
        console.error(error);
    }
};

// Event when the client is ready
client.once('ready', async () => {
    console.log(`Logged in as ${client.user.tag}`);
    await registerCommands();
});

// Event

