    let pivot := l.get l.length / 2;
    let (less, equal, more) := l.splitBy (fun x => x < pivot);
    let less := timsortStep less;
    let more := timsortStep more;
    less ++ equal ++ more

def timsort (l : List Nat) : List Nat := 
  let minRun := min (l.length / 32) 64;
  let runs := 
    iterate (fun (acc : List (List Nat)) (i : Nat) =>
